import React, { useState } from 'react';
import './Login.css';
import { ref, get } from "firebase/database";
import { database } from './firebase-config';
import CryptoJS from 'crypto-js';

function Login({ onLogin }) {
  const [chatId, setChatId] = useState('');
  const [password, setPassword] = useState('');
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);

  const handleSubmit = async (e) => {
    e.preventDefault();
    setError('');
    setLoading(true);

    const inputChatId = chatId.trim();

    if (!inputChatId || !password) {
      setError('Por favor, ingresa tu ID de Telegram y tu contraseña.');
      setLoading(false);
      return;
    }

    // Validar que el chat ID sea numérico
    if (!/^\d+$/.test(inputChatId)) {
      setError('❌ El ID de Telegram debe ser un número.');
      setLoading(false);
      return;
    }

    try {
      console.log("[LOGIN] ==== INICIO DE LOGIN ====");
      console.log("[LOGIN] Chat ID:", inputChatId);
      
      // 1. Hashear la contraseña ingresada
      const hashedPassword = CryptoJS.SHA256(password).toString();
      console.log("[LOGIN] Hash calculado:", hashedPassword.substring(0, 16) + "...");

      // 2. Buscar el usuario por chat_id
      console.log("[LOGIN] Buscando usuario en /usuarios/" + inputChatId);
      
      const userRef = ref(database, `/usuarios/${inputChatId}/perfil`);
      
      let userSnapshot = null;
      try {
        userSnapshot = await get(userRef);
        console.log("[LOGIN] Búsqueda completada");
      } catch (error) {
        console.log("[LOGIN] Error buscando usuario:", error.message);
        setError("❌ Error al conectar con la base de datos");
        setLoading(false);
        return;
      }

      if (!userSnapshot.exists()) {
        console.log("[LOGIN] ❌ Usuario no encontrado");
        setError("❌ Usuario no encontrado. Verifica tu ID de Telegram.");
        setLoading(false);
        return;
      }

      // 3. Verificar la contraseña
      const userData = userSnapshot.val();
      console.log("[LOGIN] Usuario encontrado:", {
        nombre: userData.nombre,
        hashed_password: userData.hashed_password ? userData.hashed_password.substring(0, 16) + "..." : "null"
      });
      
      if (userData.hashed_password !== hashedPassword) {
        console.log("[LOGIN] ❌ Contraseña incorrecta");
        console.log("[LOGIN]    Esperado:", userData.hashed_password);
        console.log("[LOGIN]    Recibido:", hashedPassword);
        setError("⚠️ Contraseña incorrecta");
        setLoading(false);
        return;
      }

      // 4. Login exitoso
      console.log("[LOGIN] ✅ LOGIN EXITOSO - Chat ID:", inputChatId);
      console.log("[LOGIN] ==== FIN DE LOGIN ====");
      
      // Guardar el chat_id en el almacenamiento local
      localStorage.setItem('currentUserChatId', inputChatId);
      onLogin(inputChatId);

    } catch (error) {
      console.error("[LOGIN] Error general al iniciar sesión:", error);
      console.error("[LOGIN] Stack:", error.stack);
      setError("❌ Ocurrió un error: " + error.message);
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="login-container">
      <form onSubmit={handleSubmit} className="login-form">
        <h2>Iniciar Sesión - NutrIA</h2>
        {error && <p className="error-message">{error}</p>}
        <div className="form-group">
          <label>ID de Telegram</label>
          <input
            type="text"
            value={chatId}
            onChange={(e) => setChatId(e.target.value)}
            disabled={loading}
            placeholder="Ej: 6659095348"
          />
          <small className="form-hint">Tu ID de Telegram que usaste al registrarte en el bot</small>
        </div>
        <div className="form-group">
          <label>Contraseña</label>
          <input
            type="password"
            value={password}
            onChange={(e) => setPassword(e.target.value)}
            disabled={loading}
            placeholder="Ingresa tu contraseña"
          />
        </div>
        <button type="submit" className="login-button" disabled={loading}>
          {loading ? 'Cargando...' : 'Entrar'}
        </button>
      </form>
    </div>
  );
}

export default Login;