import React, { useState, useEffect } from 'react';
import './Dashboard.css';
import { ref, onValue } from 'firebase/database';
import { database } from './firebase-config';
import logoDashboard from './assets/ia.png';
import deficitIcon from './assets/deficit.png';
import recomposicionIcon from './assets/recomposicion.png';
import superavitIcon from './assets/superavit.png';
import proteinasIcon from './assets/proteinas.png';
import carbsIcon from './assets/carbs.png';
import grasasIcon from './assets/grasas.png';

// Supongo que tienes estos componentes definidos en otro lugar
const CircleProgress = ({ progress }) => {
  const radius = 50;
  const circumference = 2 * Math.PI * radius;
  const offset = circumference - (progress / 100) * circumference;

  return (
    <svg width="120" height="120" viewBox="0 0 120 120" className="progress-circle">
      <circle
        cx="60"
        cy="60"
        r={radius}
        fill="none"
        stroke="#e6e6e6"
        strokeWidth="10"
      />
      <circle
        cx="60"
        cy="60"
        r={radius}
        fill="none"
        stroke="#90ee90"
        strokeWidth="10"
        strokeDasharray={circumference}
        strokeDashoffset={offset}
        strokeLinecap="round"
        style={{ transition: 'stroke-dashoffset 0.5s ease-in-out' }}
      />
      <text x="60" y="60" textAnchor="middle" dy=".3em" fontSize="20" fill="#2e8b57">
        {`${progress}%`}
      </text>
    </svg>
  );
};

const ProgressBar = ({ label, icon, value, max }) => {
  const progress = max > 0 ? (value / max) * 100 : 0;
  return (
    <div className="progress-bar-container">
      <div className="progress-label-row">
        <div className="progress-icon-container">
          <img src={icon} alt={`${label} icon`} className="progress-icon" />
        </div>
        <p className="progress-label">{label}</p>
        <p className="progress-value">{`${Math.round(value)} / ${Math.round(max)}`}</p>
      </div>
      <div className="bar-background">
        <div 
          className="bar-fill" 
          style={{ width: `${progress}%`, transition: 'width 0.5s ease-in-out' }}
        ></div>
      </div>
    </div>
  );
};

function Dashboard() {
  const [userData, setUserData] = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);
  const [period, setPeriod] = useState('diario');
  const [showModal, setShowModal] = useState(false);
  const [selectedFood, setSelectedFood] = useState(null);
  const [Deatils, setDeatils] = useState(null);

  const togglePeriod = () => {
  if (period === 'semanal') {
    setPeriod('mensual');
  } else if (period === 'mensual') {
    setPeriod('diario');
  } else {
    setPeriod('semanal');
  }
};

const handleFoodClick = (comida,detalle) => {
    setSelectedFood(comida);
    setDeatils(detalle);
    setShowModal(true);
  };

  const handleLogout = () => {
    localStorage.removeItem('currentUserChatId');
    window.location.reload();
  };

  useEffect(() => {
    const currentUserChatId = localStorage.getItem('currentUserChatId');

    if (!currentUserChatId) {
      setError("No hay un usuario logueado. Por favor, inicia sesión.");
      setLoading(false);
      return;
    }

    const userRef = ref(database, `usuarios/${currentUserChatId}`);

    const unsubscribe = onValue(userRef, (snapshot) => {
      if (snapshot.exists()) {
        const data = snapshot.val();
        setUserData(data);
        setLoading(false);
      } else {
        setError("No se encontraron datos para este usuario.");
        setLoading(false);
      }
    }, (err) => {
      setError("Error al cargar los datos: " + err.message);
      setLoading(false);
    });

    return () => unsubscribe();
  }, []);

  // --- COMPROBACIONES DE ESTADO (CORREGIDAS) ---
  if (loading) {
    return <p>Cargando datos...</p>;
  }

  if (error) {
    return <p style={{ color: 'red' }}>{error}</p>;
  }

  // --- AHORA QUE SABEMOS QUE USERDATA EXISTE, PODEMOS DESESTRUCTURAR ---
  const { perfil, registros, macros_necesarios } = userData;

  // ✅ METAS DIARIAS (base para cálculos semanal/mensual)
  const metasDiarias = {
    calorias: macros_necesarios?.calorias || 2000,  // Fallback a 2000 si no existen
    proteina: macros_necesarios?.proteina || 160,   // Fallback a 160 si no existen
    grasa: macros_necesarios?.grasa || 65,          // Fallback a 65 si no existen
    carbohidratos: macros_necesarios?.carbohidratos || 200,  // Fallback a 200 si no existen
  };

  // ✅ FUNCIÓN PARA OBTENER TODOS LOS DÍAS DE UN RANGO
  const obtenerDiasDelPeriodo = (period) => {
    const today = new Date();
    const dias = [];
    
    let diasAlAtras = 0;
    if (period === 'semanal') {
      diasAlAtras = 7;
    } else if (period === 'mensual') {
      // ✅ MEJORADO: Usar días REALES del mes actual en lugar de 28 fijos
      const ultimoDiaDelMes = new Date(today.getFullYear(), today.getMonth() + 1, 0);
      diasAlAtras = ultimoDiaDelMes.getDate();
    } else {
      // Diario - solo hoy
      diasAlAtras = 1;
    }
    
    for (let i = 0; i < diasAlAtras; i++) {
      const fecha = new Date(today);
      fecha.setDate(fecha.getDate() - i);
      const year = fecha.getFullYear();
      const month = String(fecha.getMonth() + 1).padStart(2, '0');
      const day = String(fecha.getDate()).padStart(2, '0');
      const dateString = `${year}-${month}-${day}`;
      dias.push(dateString);
    }
    return dias;
  };

  // ✅ FUNCIÓN PARA SUMAR TOTALES DE MÚLTIPLES DÍAS
  const calcularTotalesPeriodo = (period) => {
    const dias = obtenerDiasDelPeriodo(period);
    let totalCalorias = 0;
    let totalProteina = 0;
    let totalGrasa = 0;
    let totalCarbohidratos = 0;
    
    dias.forEach(fecha => {
      const registroDia = registros?.diario?.[fecha] || {};
      totalCalorias += registroDia.calorias || 0;
      totalProteina += registroDia.proteina || 0;
      totalGrasa += registroDia.grasa || 0;
      totalCarbohidratos += registroDia.carbohidratos || 0;
    });
    
    return {
      calorias: totalCalorias,
      proteina: totalProteina,
      grasa: totalGrasa,
      carbohidratos: totalCarbohidratos
    };
  };

  // ✅ CALCULAR METAS PARA EL PERÍODO SELECCIONADO
  const metasPeriodo = {
    calorias: metasDiarias.calorias * (period === 'semanal' ? 7 : period === 'mensual' ? 28 : 1),
    proteina: metasDiarias.proteina * (period === 'semanal' ? 7 : period === 'mensual' ? 28 : 1),
    grasa: metasDiarias.grasa * (period === 'semanal' ? 7 : period === 'mensual' ? 28 : 1),
    carbohidratos: metasDiarias.carbohidratos * (period === 'semanal' ? 7 : period === 'mensual' ? 28 : 1),
  };

  // ✅ OBTENER TOTALES DEL PERÍODO ACTUAL
  const totalesPeriodo = calcularTotalesPeriodo(period);
  
  // Para retrocompatibilidad, mantener totalesDeHoy también
  const today = new Date();
  const year = today.getFullYear();
  const month = String(today.getMonth() + 1).padStart(2, '0');
  const day = String(today.getDate()).padStart(2, '0');
  const hoy = `${year}-${month}-${day}`;
  
  // ✅ CORRECCIÓN: Buscar en /registros/diario/{fecha}/ no en /registros/{fecha}/
  const registrosDeHoy = registros?.diario?.[hoy] || {};
  const totalesDeHoy = {
    total_calorias: registrosDeHoy.calorias || 0,
    total_proteina: registrosDeHoy.proteina || 0,
    total_grasa: registrosDeHoy.grasa || 0,
    total_carbohidratos: registrosDeHoy.carbohidratos || 0
  };
  const comidasDeHoy = Object.entries(registrosDeHoy?.comidas || {});

  const selectedDieta = perfil?.tipoDieta || "Déficit calórico";
  
  const getDietaIcon = (dieta) => {
    switch (dieta) {
      case "Déficit calórico": return deficitIcon;
      case "Recomposición muscular": return recomposicionIcon;
      case "Superávit calórico": return superavitIcon;
      default: return null;
    }
  };

  return (
    <div className="dashboard-container">
      <header className="dashboard-header">
        <h1 className="dashboard-title">
          <img src={logoDashboard} alt="Logo de Nutria" className="dashboard-logo" />
          NutrIA Dashboard
        </h1>
        <div className="user-info">
          <span className="user-name">Hola, {perfil?.nombre}!</span>
          <button onClick={handleLogout} className="logout-button">Cerrar Sesión</button>
        </div>
      </header>
      <div className="bento-grid">
        {/* Columna 1: Información Personal */}
        <div className="bento-item user-project-container">
          <div className="inner-bento-item">
            <h3 className="bento-title">Datos del Usuario</h3>
            <p><strong>Altura:</strong> {perfil?.altura} cm</p>
            <p><strong>Peso:</strong> {perfil?.peso} kg</p>
            <p><strong>Sexo:</strong> {perfil?.genero}</p>
            <p><strong>Actividad Física:</strong> {perfil?.nivelActividad}</p>
          </div>
          <div className="inner-bento-item">
            <h3 className="bento-title">Datos del Proyecto</h3>
            <p><strong>Plataforma:</strong> Bot de Telegram</p>
            <p><strong>Desarrolladores:</strong> Jaime García - Daniel Chavez Jesúa Camuendo - Anthony Loja</p>
          </div>
        </div>
        {/* Cuadro 2: Dieta Seleccionada */}
        <div className="bento-item selected-dieta-box">
          <h3 className="bento-title">Tu Dieta Actual</h3>
          <img src={getDietaIcon(selectedDieta)} alt={`${selectedDieta} icon`} className="dieta-icon" />
          <p className="selected-dieta-text">{selectedDieta}</p>
        </div>
        {/* Cuadro 3: Progreso y Metas */}
        <div className="bento-item progress-and-goals-box">
          <div className="progress-header">
            <h3 className="bento-title">Progreso  {period === 'semanal' ? 'Semanal' : period === 'mensual' ? 'Mensual' : 'Diario'}</h3>
            <button onClick={togglePeriod} className="period-toggle-btn">
             {period === 'semanal' ? 'Ver Mensual' : period === 'mensual' ? 'Ver Diario' : 'Ver Semanal'}
           </button>
          </div>
          <div className="progress-content">
            <div className="circle-progress-container">
              <p>Calorías</p>
              <CircleProgress progress={Math.round(
                (totalesPeriodo.calorias / metasPeriodo.calorias) * 100
              )} />
              <p>{totalesPeriodo.calorias} / {metasPeriodo.calorias} kcal</p>
            </div>
            <div className="macro-bars-container">
              <ProgressBar
                label="Proteínas"
                icon={proteinasIcon}
                value={totalesPeriodo.proteina}
                max={metasPeriodo.proteina}
              />
              <ProgressBar
                label="Carbohidratos"
                icon={carbsIcon}
                value={totalesPeriodo.carbohidratos}
                max={metasPeriodo.carbohidratos}
              />
              <ProgressBar
                label="Grasas"
                icon={grasasIcon}
                value={totalesPeriodo.grasa}
                max={metasPeriodo.grasa}
              />
            </div>
          </div>
        </div>
        <div className="bento-item recommended-meals-box">
          <h3 className="bento-title">Comidas Recomendadas</h3>
          <table>
            <thead>
              <tr>
                <th>Comida</th>
                <th>Tipo de Comida</th>
              </tr>
            </thead>
           <tbody>
      {Object.entries(comidasDeHoy)
        .filter(([_, detallesComida]) => detallesComida[1].tipo_comida !== 'No especificado')
        .map(([_, detallesComida], index) => {
      return (
        <tr key={index}>
          <td>{detallesComida[0]}</td>
          <td>{detallesComida[1].tipo_comida}</td>
        </tr>
      );
    })}
      {Object.entries(comidasDeHoy).filter(([_, detallesComida]) => detallesComida.tipo_comida !== 'No especificado').length === 0 && (
        <tr>
          <td colSpan="3">No hay comidas con tipo de comida especificado.</td>
        </tr>
      )}
    </tbody>
          </table>
        </div>
        {/* Cuadro 4: Comidas Registradas hoy */}
        <div className="bento-item meals-box">
          <h3 className="bento-title">Comidas Registradas</h3>
          <table>
            <thead>
              <tr>
                <th>Comida</th>
                <th>Fecha</th>
                <th>Calorías</th>
              </tr>
            </thead>
             <tbody>
      {comidasDeHoy.length > 0 ? (
        comidasDeHoy.map(([nombre,detalle], index) => (
            <tr key={index} onClick={() => handleFoodClick(nombre,detalle)} style={{ cursor: 'pointer' }}>
              <td>{nombre}</td>
              <td>{hoy}</td>
              <td>{detalle.calorias} kcal</td>
            </tr>
          ))
      ) : (
        <tr>
          <td colSpan="4">No hay comidas con tipo de comida especificado.</td>
        </tr>
      )}
    </tbody>
          </table>
      </div>
    </div>
     {/* Ventana flotante (Modal) */}
      {showModal && selectedFood && Deatils &&(
        <div className="modal-overlay">
          <div className="modal-content">
            <button className="modal-close-btn" onClick={() => setShowModal(false)}>
              &times;
            </button>
            <h3 className="modal-title">Detalles de: {selectedFood}</h3>
            <p><strong>Calorías:</strong> {Deatils.calorias} kcal</p>
            <p><strong>Proteínas:</strong> {Deatils.proteinas} g</p>
            <p><strong>Carbohidratos:</strong> {Deatils.carbohidratos} g</p>
            <p><strong>Grasas:</strong> {Deatils.grasas} g</p>
          </div>
        </div>
      )}
    </div>
  );
}

export default Dashboard;